from contextlib import asynccontextmanager from fastapi import FastAPI
@asynccontextmanager async def lifespan(app: FastAPI): await init_db() await init_message_bus() yield await close_message_bus() await close_db()
app = FastAPI(title="User Service", version="1.0.0", lifespan=lifespan) app.include_router(health_router, tags=["health"]) app.include_router(router, prefix="/api/v1", tags=["users"])
